import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Dashboard.css"
function Dashboard() {
  const [users, setUsers] = useState([]);
  const [search, setSearch] = useState("");
  const [sortField, setSortField] = useState("name");
  const [sortOrder, setSortOrder] = useState("asc");
  const navigate = useNavigate();

  useEffect(() => {
    fetch("https://jsonplaceholder.typicode.com/users")
      .then(res => res.json())
      .then(data => setUsers(data));
  }, []);

  const filteredUsers = users
    .filter(user =>
      user.name.toLowerCase().includes(search.toLowerCase()) ||
      user.email.toLowerCase().includes(search.toLowerCase())
    )
    .sort((a, b) => {
      let valA = sortField === "company" ? a.company.name : a.name;
      let valB = sortField === "company" ? b.company.name : b.name;

      if (sortOrder === "asc") return valA.localeCompare(valB);
      return valB.localeCompare(valA);
    });

  const handleSort = (field) => {
    if (sortField === field) {
      setSortOrder(sortOrder === "asc" ? "desc" : "asc");
    } else {
      setSortField(field);
      setSortOrder("asc");
    }
  };
  const formatPhone = (phone) => {
  // Example: "493-170-9623 x156"
  const parts = phone.split("x");

  const number = parts[0].replace(/\D/g, ""); // remove non-digits
  const extension = parts[1] ? parts[1].trim() : "";

  const countryCode = "+1"; // change if needed

  if (extension) {
    return `${countryCode}${number},${extension}`;
  }
  return `${countryCode}${number}`;
};

  return (
    <div className="container">
      <h1>User Directory</h1>

      <input
        type="text"
        placeholder="Search..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      <table border="1">
        <thead>
          <tr>
            <th onClick={() => handleSort("name")}>Name</th>
            <th>Email</th>
            <th>Phone</th>
            <th onClick={() => handleSort("company")}>Company</th>
          </tr>
        </thead>
        <tbody>
          {filteredUsers.map(user => (
            <tr key={user.id} onClick={() => navigate(`/user/${user.id}`)}>
              <td>{user.name}</td>
              <td>{user.email}</td>
              <td>
                <a
                href={`tel:${formatPhone(user.phone)}`}
                onClick={(e) => e.stopPropagation()} // prevents row click navigation
                className="phone-link">
                </a>
                {user.phone}</td>
                
              <td>{user.company.name}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Dashboard;
